// n8n-marcin/12-kalendarz-sesji.json — Parsuj Sesje
// Purpose: Extract sessions from eSesja HTML, check Qdrant for already-notified
// NOT for: fetching agenda (that's the next node)

const html = $input.first().json.data || $input.first().json.body || '';
const qdrantUrl = 'http://qdrant:6333';

// Parse sessions from HTML
// Pattern: /posiedzenie/UUID with date text nearby
const sessionRegex = /\/posiedzenie\/([a-f0-9-]+)/g;
const dateRegex = /(\d{1,2})\s+(stycznia|lutego|marca|kwietnia|maja|czerwca|lipca|sierpnia|wrze[sś]nia|pa[zź]dziernika|listopada|grudnia)\s+(\d{4})[^\d]*(\d{2}:\d{2})?/gi;

const months = {
  'stycznia': '01', 'lutego': '02', 'marca': '03', 'kwietnia': '04',
  'maja': '05', 'czerwca': '06', 'lipca': '07', 'sierpnia': '08',
  'września': '09', 'wrzesnia': '09', 'października': '10', 'pazdziernika': '10',
  'listopada': '11', 'grudnia': '12'
};

// Extract all session links
const sessions = [];
const seen = new Set();

// Split HTML into chunks around session links for context
const chunks = html.split(/\/posiedzenie\//);
for (let i = 1; i < chunks.length; i++) {
  const uuid = chunks[i].match(/^([a-f0-9-]+)/)?.[1];
  if (!uuid || seen.has(uuid)) continue;
  seen.add(uuid);

  // Look for date in surrounding context (before and after the link)
  const context = (chunks[i - 1]?.slice(-500) || '') + chunks[i].slice(0, 500);
  const dateMatch = context.match(/(\d{1,2})\s+(stycznia|lutego|marca|kwietnia|maja|czerwca|lipca|sierpnia|wrze[sś]nia|pa[zź]dziernika|listopada|grudnia)\s+(\d{4})/i);
  const timeMatch = context.match(/godz\.?\s*(\d{2}:\d{2})/i);

  // Extract title (text before/around the link)
  const titleMatch = context.match(/(Sesja|Posiedzenie)\s+nr\s+[IVXLC]+/i);
  // Extract body name: look for text inside <a> tags or plain text
  let bodyName = '';
  const bodyAnchor = context.match(/>\s*(Rada Powiatu[^<]*|Komisja[^<]{3,60})</i);
  if (bodyAnchor) {
    bodyName = bodyAnchor[1].trim();
  } else {
    const bodyPlain = context.match(/(Rada Powiatu|Komisja\s+\w[^<,]{3,60})/i);
    if (bodyPlain) bodyName = bodyPlain[1].trim();
  }

  if (dateMatch) {
    const day = dateMatch[1].padStart(2, '0');
    const monthName = dateMatch[2].toLowerCase();
    const month = months[monthName] || '01';
    const year = dateMatch[3];
    const dateIso = `${year}-${month}-${day}`;
    const time = timeMatch?.[1] || '09:00';

    sessions.push({
      uuid,
      url: `https://powiatkrasnicki.esesja.pl/posiedzenie/${uuid}`,
      date: dateIso,
      time,
      title: titleMatch?.[0] || 'Posiedzenie',
      body: bodyName || 'Rada Powiatu',
      dateObj: new Date(`${dateIso}T${time}:00`)
    });
  }
}

// Filter: last 14 days + future (catch newly added sessions)
const now = new Date();
const cutoff = new Date(now.getTime() - 14 * 86400000).toISOString().slice(0, 10);
const upcoming = sessions.filter(s => s.date >= cutoff).sort((a, b) => a.dateObj - b.dateObj);

if (upcoming.length === 0) {
  return [{ json: { sessions: [], newSessions: [], message: 'Brak nadchodzących sesji' } }];
}

// Check Qdrant for already-notified sessions
let notified = [];
try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: qdrantUrl + '/collections/krasnik_news/points/scroll',
    body: {
      limit: 100, with_payload: true, with_vector: false,
      filter: { must: [{ key: 'category', match: { value: 'sesja-rady-notified' } }] }
    },
    json: true
  });
  notified = (result.result?.points || []).map(p => p.payload?.session_uuid);
} catch (e) { console.log('Qdrant check error:', e.message); }

const newSessions = upcoming.filter(s => !notified.includes(s.uuid));

return [{ json: { sessions: upcoming, newSessions, allNotified: notified } }];

// n8n-marcin/12-kalendarz-sesji.json — Pobierz Agendy + Powiadom
// Purpose: Fetch agenda for new sessions, format Telegram message, store in Qdrant
// NOT for: parsing session list (that's Parsuj Sesje)

const geminiKey = $env.GEMINI_API_KEY || '';
const qdrantUrl = 'http://qdrant:6333';
const newSessions = $json.newSessions || [];
const allSessions = $json.sessions || [];

if (newSessions.length === 0) {
  return [{ json: { telegram: '', stored: 0 } }];
}

// Fetch agenda for each new session
const sessionsWithAgenda = [];
for (const s of newSessions) {
  let agenda = '(nie udało się pobrać porządku obrad)';
  try {
    const html = await this.helpers.httpRequest({
      method: 'GET', url: s.url,
      options: { response: { response: { responseFormat: 'text' } } }
    });
    const body = typeof html === 'string' ? html : (html.data || html.body || '');

    // Extract agenda items — they follow 'Porządek obrad' heading
    const agendaSection = body.split(/[Pp]orz[aą]dek\s+obrad/i)[1] || '';
    // Find numbered items (1. ..., 2. ..., etc)
    const items = [];
    const itemRegex = /(\d+)\.\s*([^<\n]{5,200})/g;
    let match;
    while ((match = itemRegex.exec(agendaSection)) !== null && items.length < 15) {
      // Clean HTML tags
      const text = match[2].replace(/<[^>]+>/g, '').trim();
      if (text.length > 3) items.push(`${match[1]}. ${text}`);
    }
    if (items.length > 0) agenda = items.join('\n');
  } catch (e) { console.log('Agenda fetch error for', s.uuid, ':', e.message); }

  sessionsWithAgenda.push({ ...s, agenda });
}

// Format Telegram message
const daysOfWeek = ['niedziela', 'poniedziałek', 'wtorek', 'środa', 'czwartek', 'piątek', 'sobota'];

let msg = '🏛️ *Nowe sesje / posiedzenia*\n\n';
for (const s of sessionsWithAgenda) {
  const d = new Date(s.date + 'T' + s.time + ':00');
  const dayName = daysOfWeek[d.getDay()];
  const daysUntil = Math.ceil((d - new Date()) / 86400000);
  const urgency = daysUntil <= 1 ? '🔴 JUTRO!' : daysUntil <= 3 ? '🟡 za ' + daysUntil + ' dni' : '🟢 za ' + daysUntil + ' dni';

  msg += `*${s.title} — ${s.body}*\n`;
  msg += `📅 ${s.date} (${dayName}) godz. ${s.time}\n`;
  msg += `${urgency}\n`;
  msg += `🔗 ${s.url}\n`;
  msg += `\n*Porządek obrad:*\n${s.agenda}\n\n`;
}

// Also show upcoming sessions summary
if (allSessions.length > sessionsWithAgenda.length) {
  msg += '\n📆 *Wszystkie nadchodzące:*\n';
  for (const s of allSessions) {
    msg += `• ${s.date} ${s.time} — ${s.title} (${s.body})\n`;
  }
}

// Truncate for Telegram (4096 limit)
if (msg.length > 4000) {
  msg = msg.substring(0, 3950) + '\n\n... (skrócono, pełna lista na eSesja)';
}

// Store notified sessions in Qdrant
// SHARED: simpleHash+makeUUID — keep identical across all Code nodes that use it
function simpleHash(str) {
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0; i < str.length; i++) {
    const ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507);
  h1 ^= Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507);
  h2 ^= Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  return (h2 >>> 0).toString(16).padStart(8, '0') + (h1 >>> 0).toString(16).padStart(8, '0') + '0000000000000000';
}
function makeUUID(input) {
  const h = simpleHash(input);
  return h.slice(0,8)+'-'+h.slice(8,12)+'-'+h.slice(12,16)+'-'+h.slice(16,20)+'-'+h.slice(20,32);
}

let stored = 0;
for (const s of sessionsWithAgenda) {
  try {
    // Generate deterministic embedding (zero vector — we only need payload, not similarity)
    const zeroVector = new Array(768).fill(0);
    await this.helpers.httpRequest({
      method: 'PUT',
      url: qdrantUrl + '/collections/krasnik_news/points',
      body: {
        points: [{
          id: makeUUID('sesja-' + s.uuid),
          vector: zeroVector,
          payload: {
            category: 'sesja-rady-notified',
            session_uuid: s.uuid,
            title: s.title + ' — ' + s.body,
            date: s.date,
            time: s.time,
            url: s.url,
            agenda: s.agenda,
            notified_at: new Date().toISOString()
          }
        }]
      },
      json: true
    });
    stored++;
  } catch (e) { console.log('Qdrant store error:', e.message); }
}

return [{ json: { telegram: msg, stored, count: sessionsWithAgenda.length } }];
